#ifndef MQTT_CLIENT_H
#define MQTT_CLIENT_H

#include <WiFi.h>
#include <PubSubClient.h>

class MqttClient {
public:
    void setup(const char* ssid, const char* password, const char* broker, int port, const char* topic_publish, const char* topic_subscribe);
    void loop();
    String getMessage() const;
    bool isConnected() const;

private:
    WiFiClient espClient;
    PubSubClient client(espClient);
    const char* ssid;
    const char* password;
    const char* broker;
    int port;
    const char* topic_publish;
    const char* topic_subscribe;
    String message;
    bool connected = false;
};

#endif // MQTT_CLIENT_H

firmware_template.source:
#include "mqtt_client.h"

void MqttClient::setup(const char* ssid, const char* password, const char* broker, int port, const char* topic_publish, const char* topic_subscribe) {
    this->ssid = ssid;
    this->password = password;
    this->broker = broker;
    this->port = port;
    this->topic_publish = topic_publish;
    this->topic_subscribe = topic_subscribe;

    WiFi.begin(ssid, password);
    while (WiFi.status() != WL_CONNECTED) {
        delay(1000);
        Serial.println("[mqtt_client] Connecting to WiFi...");
    }
    Serial.println("[mqtt_client] Connected to WiFi");

    client.setServer(broker, port);
    client.setCallback([](char* topic, byte* payload, unsigned int length) {
        // Handle incoming messages here
    });
}

void MqttClient::loop() {
    if (!client.connected()) {
        reconnect();
    }
    client.loop();

    if (client.connected()) {
        // Publish data or handle subscriptions as needed
    }
}

String MqttClient::getMessage() const {
    return message;
}

bool MqttClient::isConnected() const {
    return connected;
}

void MqttClient::reconnect() {
    while (!client.connected()) {
        Serial.println("[mqtt_client] Attempting MQTT connection...");
        if (client.connect("ESP32Client")) {
            Serial.println("[mqtt_client] Connected to MQTT broker");
            client.subscribe(topic_subscribe);
            connected = true;
        } else {
            Serial.print("[mqtt_client] Failed, rc=");
            Serial.print(client.state());
            Serial.println(" try again in 5 seconds");
            delay(5000);
        }
    }
}
